class CustomAuthorizationCodeServices extends InMemoryAuthorizationCodeServices {
    private final Map<String, CodeEntry> codes = new ConcurrentHashMap<>();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public CustomAuthorizationCodeServices() {
        scheduler.scheduleAtFixedRate(this::cleanupExpiredCodes, 60, 60, TimeUnit.SECONDS);
    }

    @Override
    public void addAuthorizationCode(String code, ClientDetails client) {
        codes.put(code, new CodeEntry(code, System.currentTimeMillis() + 600000, client));
    }

    @Override
    public ClientDetails getAuthorizationCode(String code) {
        CodeEntry entry = codes.get(code);
        if (entry != null && System.currentTimeMillis() < entry.expirationTime) {
            return entry.client;
        }
        return null;
    }

    @Override
    public void removeAuthorizationCode(String code) {
        codes.remove(code);
    }

    private void cleanupExpiredCodes() {
        long currentTime = System.currentTimeMillis();
        codes.entrySet().removeIf(entry -> currentTime >= entry.getValue().expirationTime);
    }

    private static class CodeEntry {
        final String code;
        final long expirationTime;
        final ClientDetails client;

        CodeEntry(String code, long expirationTime, ClientDetails client) {
            this.code = code;
            this.expirationTime = expirationTime;
            this.client = client;
        }
    }
}

